import{_ as t,o as n,c as i,a0 as r}from"./chunks/framework.CSGB4SNl.js";const h=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"drone-pro/drone-user-uni/uni_modules/uni-list/readme.md","filePath":"drone-pro/drone-user-uni/uni_modules/uni-list/readme.md"}'),l={name:"drone-pro/drone-user-uni/uni_modules/uni-list/readme.md"};function d(a,e,o,u,p,s){return n(),i("div",null,[...e[0]||(e[0]=[r('<h2 id="list-列表" tabindex="-1">List 列表 <a class="header-anchor" href="#list-列表" aria-label="Permalink to &quot;List 列表&quot;">​</a></h2><blockquote><p><strong>组件名：uni-list</strong> 代码块： <code>uList</code>、<code>uListItem</code> 关联组件：<code>uni-list-item</code>、<code>uni-badge</code>、<code>uni-icons</code>、<code>uni-list-chat</code>、<code>uni-list-ad</code></p></blockquote><p>List 列表组件，包含基本列表样式、可扩展插槽机制、长列表性能优化、多端兼容。</p><p>在vue页面里，它默认使用页面级滚动。在app-nvue页面里，它默认使用原生list组件滚动。这样的长列表，在滚动出屏幕外后，系统会回收不可见区域的渲染内存资源，不会造成滚动越长手机越卡的问题。</p><p>uni-list组件是父容器，里面的核心是uni-list-item子组件，它代表列表中的一个可重复行，子组件可以无限循环。</p><p>uni-list-item有很多风格，uni-list-item组件通过内置的属性，满足一些常用的场景。当内置属性不满足需求时，可以通过扩展插槽来自定义列表内容。</p><p>内置属性可以覆盖的场景包括：导航列表、设置列表、小图标列表、通信录列表、聊天记录列表。</p><p>涉及很多大图或丰富内容的列表，比如类今日头条的新闻列表、类淘宝的电商列表，需要通过扩展插槽实现。</p><p>下文均有样例给出。</p><p>uni-list不包含下拉刷新和上拉翻页。上拉翻页另见组件：<a href="https://ext.dcloud.net.cn/plugin?id=29" target="_blank" rel="noreferrer">uni-load-more</a></p><h3 id="点击查看详细文档" tabindex="-1"><a href="https://uniapp.dcloud.io/component/uniui/uni-indexed-list" target="_blank" rel="noreferrer">点击查看详细文档</a> <a class="header-anchor" href="#点击查看详细文档" aria-label="Permalink to &quot;[点击查看详细文档](https://uniapp.dcloud.io/component/uniui/uni-indexed-list)&quot;">​</a></h3><h4 id="如使用过程中有任何问题-或者您对uni-ui有一些好的建议-欢迎加入-uni-ui-交流群-871950839" tabindex="-1">如使用过程中有任何问题，或者您对uni-ui有一些好的建议，欢迎加入 uni-ui 交流群：871950839 <a class="header-anchor" href="#如使用过程中有任何问题-或者您对uni-ui有一些好的建议-欢迎加入-uni-ui-交流群-871950839" aria-label="Permalink to &quot;如使用过程中有任何问题，或者您对uni-ui有一些好的建议，欢迎加入 uni-ui 交流群：871950839&quot;">​</a></h4><h2 id="基于uni-list扩展的页面模板" tabindex="-1">基于uni-list扩展的页面模板 <a class="header-anchor" href="#基于uni-list扩展的页面模板" aria-label="Permalink to &quot;基于uni-list扩展的页面模板&quot;">​</a></h2><p>通过扩展插槽，可实现多种常见样式的列表</p><p><strong>新闻列表类</strong></p><ol><li>云端一体混合布局：<a href="https://ext.dcloud.net.cn/plugin?id=2546" target="_blank" rel="noreferrer">https://ext.dcloud.net.cn/plugin?id=2546</a></li><li>云端一体垂直布局，大图模式：<a href="https://ext.dcloud.net.cn/plugin?id=2583" target="_blank" rel="noreferrer">https://ext.dcloud.net.cn/plugin?id=2583</a></li><li>云端一体垂直布局，多行图文混排：<a href="https://ext.dcloud.net.cn/plugin?id=2584" target="_blank" rel="noreferrer">https://ext.dcloud.net.cn/plugin?id=2584</a></li><li>云端一体垂直布局，多图模式：<a href="https://ext.dcloud.net.cn/plugin?id=2585" target="_blank" rel="noreferrer">https://ext.dcloud.net.cn/plugin?id=2585</a></li><li>云端一体水平布局，左图右文：<a href="https://ext.dcloud.net.cn/plugin?id=2586" target="_blank" rel="noreferrer">https://ext.dcloud.net.cn/plugin?id=2586</a></li><li>云端一体水平布局，左文右图：<a href="https://ext.dcloud.net.cn/plugin?id=2587" target="_blank" rel="noreferrer">https://ext.dcloud.net.cn/plugin?id=2587</a></li><li>云端一体垂直布局，无图模式，主标题+副标题：<a href="https://ext.dcloud.net.cn/plugin?id=2588" target="_blank" rel="noreferrer">https://ext.dcloud.net.cn/plugin?id=2588</a></li></ol><p><strong>商品列表类</strong></p><ol><li>云端一体列表/宫格视图互切：<a href="https://ext.dcloud.net.cn/plugin?id=2651" target="_blank" rel="noreferrer">https://ext.dcloud.net.cn/plugin?id=2651</a></li><li>云端一体列表（宫格模式）：<a href="https://ext.dcloud.net.cn/plugin?id=2671" target="_blank" rel="noreferrer">https://ext.dcloud.net.cn/plugin?id=2671</a></li><li>云端一体列表（列表模式）：<a href="https://ext.dcloud.net.cn/plugin?id=2672" target="_blank" rel="noreferrer">https://ext.dcloud.net.cn/plugin?id=2672</a></li></ol>',18)])])}const g=t(l,[["render",d]]);export{h as __pageData,g as default};
